# main.py# === Import your project modules ===from loaders.raman_loader import select_directory, select_file, load_ramanfrom preprocessors.raman_preprocess import preprocess_pipeline_1, preprocess_pipeline_2from preprocessors.aligner import align_xyfrom models.wrappers import PLS_model, Ridge_model, MLPRegressor_model, KNNRegressor_model, SVMRegressor_modelimport osimport pandas as pd# === Step 1: Select Raw Data Directory ===print("\n📂 Select the directory containing your raw Raman .spc files:")directory = select_directory()# === Step 2: Set up Output Directories ===spectra_dir = os.path.join(directory, "Raman_Spectra")results_dir = os.path.join(directory, "Model_Results")os.makedirs(spectra_dir, exist_ok=True)os.makedirs(results_dir, exist_ok=True)# === Step 3: Load Raw Raman Spectra ===sample_spectra, shifts = load_raman(directory, spectra_dir)# === Step 4: Preprocess Spectra ===preprocessed_sample_spectra, cropped_axis = preprocess_pipeline_2(sample_spectra, spectra_dir)# === Step 5: Load Target Table (GCMS or Metadata) ===print("\n📄 Select the GCMS or Target Excel file:")gcms_path = select_file()gcms_df = pd.read_excel(gcms_path)gcms_df.set_index('ID', inplace=True)# === Step 6: Align X and Y ===filtered_X, filtered_Y, filtered_sample_ids = align_xy(preprocessed_sample_spectra, gcms_df)# === Step 7: Modeling Loop ===print("\n🚀 Starting model training for each target analyte...")for analyte in filtered_Y.columns:    print(f"\n🔬 Training models for target: {analyte}")    Y_target = filtered_Y[analyte].values.reshape(-1, 1)    # Run a few models    pls = PLS_model(filtered_X, Y_target, results_dir, cropped_axis, analyte=analyte)    #ridge = Ridge_model(filtered_X, Y_target, results_dir, cropped_axis, analyte=analyte)    mlp = MLPRegressor_model(filtered_X, Y_target, results_dir, cropped_axis, analyte=analyte)    #knn = KNNRegressor_model(filtered_X, Y_target, results_dir, cropped_axis, analyte=analyte)    svm = SVMRegressor_model(filtered_X, Y_target, results_dir, cropped_axis, analyte=analyte)# === Final Message ===print("\n✅ All models finished! Results saved in:")print(f"  - Spectra: {spectra_dir}")print(f"  - Model Results: {results_dir}")